 1	import React, { FC } from 'react';
 2	
 3	import { V1CPU } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { Button, ButtonVariant, Popover, PopoverPosition } from '@patternfly/react-core';
 6	import { HelpIcon } from '@patternfly/react-icons';
 7	
 8	import './CPUTopologyHelperText.scss';
 9	
10	type CPUTopologyHelperTextProps = {
11	  cpu: V1CPU;
12	};
13	
14	const CPUTopologyHelperText: FC<CPUTopologyHelperTextProps> = ({ cpu }) => {
15	  const { t } = useKubevirtTranslation();
16	  const { cores, sockets, threads } = cpu || {};
17	
18	  const totalCPU = cores * sockets * threads;
19	
20	  return (
21	    <div className="cpu-topology-helper-text">
22	      {t('Total vCPU is {{totalCPU}}', { totalCPU: totalCPU })}
23	      <Popover
24	        bodyContent={<>{t('CPUs = sockets x threads x cores.')}</>}
25	        hasAutoWidth
26	        position={PopoverPosition.bottom}
27	      >
28	        <Button className="cpu-topology-helper-text__button" variant={ButtonVariant.plain}>
29	          <HelpIcon />
30	        </Button>
31	      </Popover>
32	    </div>
33	  );
34	};
35	
36	export default CPUTopologyHelperText;

